from collections import defaultdict, deque
from typing import Dict, List

class Solution:
    def allBuildOrders(self, modules: List[str], dependencies: List[List[str]]) -> List[str]:
        if not modules:
            return []
        # indeg[x]：当前图中还有多少条依赖指向 x
        indeg: Dict[str, int] = {m: 0 for m in modules}
        # g[u]：所有从 u 出发的边（即 u 必须先于其中的节点）
        g: Dict[str, List[str]] = defaultdict(list)
        for a, b in dependencies:
            if a not in indeg or b not in indeg:
                continue
            g[b].append(a)
            indeg[a] += 1

        # 使用 Kahn 算法判环
        q = deque([m for m in modules if indeg[m] == 0])
        tmp = indeg.copy()
        seen = 0
        while q:
            u = q.popleft()
            seen += 1
            for v in g[u]:
                tmp[v] -= 1
                if tmp[v] == 0:
                    q.append(v)
        if seen != len(modules):
            # 存在环，无合法构建顺序
            return []

        indeg_mut = indeg.copy()
        path: List[str] = []  # 当前构建路径
        out: List[str] = []   # 所有合法顺序结果

        def dfs() -> None:
            if len(path) == len(modules):
                # 完成一种构建顺序，加入结果
                out.append(" ".join(path))
                return
            # 找出当前所有可选（入度为0且未使用）的模块
            cand = sorted([m for m in modules if m not in path and indeg_mut[m] == 0])
            for m in cand:
                path.append(m)
                for nei in g[m]:
                    indeg_mut[nei] -= 1
                dfs()
                for nei in g[m]:
                    indeg_mut[nei] += 1
                path.pop()

        dfs()
        return sorted(out)
