```cpp
#include <algorithm>
#include <queue>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <vector>
using namespace std;

class Solution {
public:
    vector<string> allBuildOrders(vector<string>& modules, vector<vector<string>>& dependencies) {
        if (modules.empty()) return {};
        unordered_map<string, int> indeg;
        unordered_map<string, vector<string>> g;
        for (auto& m : modules) indeg[m] = 0;
        for (auto& e : dependencies) {
            const string& a = e[0];
            const string& b = e[1];
            if (!indeg.count(a) || !indeg.count(b)) continue;
            g[b].push_back(a);
            indeg[a]++;
        }

        // Kahn 判环
        auto tmp = indeg;
        queue<string> q;
        for (auto& m : modules)
            if (tmp[m] == 0) q.push(m);
        int seen = 0;
        while (!q.empty()) {
            string u = q.front(); q.pop();
            seen++;
            for (auto& v : g[u])
                if (--tmp[v] == 0) q.push(v);
        }
        if (seen != (int)modules.size()) return {};

        unordered_map<string, int> indegMut = indeg;
        vector<string> path, out;
        dfsAll(modules, g, indegMut, path, out);
        sort(out.begin(), out.end());
        return out;
    }

private:
    void dfsAll(vector<string>& modules, unordered_map<string, vector<string>>& g,
                unordered_map<string, int>& indegMut, vector<string>& path, vector<string>& out) {
        if ((int)path.size() == (int)modules.size()) {
            string line;
            for (size_t i = 0; i < path.size(); i++) {
                if (i) line += ' ';
                line += path[i];
            }
            out.push_back(line);
            return;
        }
        unordered_set<string> inPath(path.begin(), path.end());
        vector<string> cand;
        for (auto& m : modules)
            if (!inPath.count(m) && indegMut[m] == 0) cand.push_back(m);
        sort(cand.begin(), cand.end());
        for (auto& m : cand) {
            path.push_back(m);
            for (auto& nei : g[m]) indegMut[nei]--;
            dfsAll(modules, g, indegMut, path, out);
            for (auto& nei : g[m]) indegMut[nei]++;
            path.pop_back();
        }
    }
};
