```javascript
/**
 * @param {string[]} modules 模块名称数组
 * @param {string[][]} dependencies 依赖关系 [x, y] 表示 x 依赖 y
 * @return {string[]} 所有合法构建顺序（以空格分隔），按字典序排序
 */
var allBuildOrders = function(modules, dependencies) {
    const n = modules.length;
    const nameToIdx = new Map();
    modules.forEach((m, i) => nameToIdx.set(m, i));

    // 建图
    const adj = Array.from({ length: n }, () => []);
    const indeg = new Array(n).fill(0);
    for (const [a, b] of dependencies) {
        const bi = nameToIdx.get(b);
        const ai = nameToIdx.get(a);
        if (bi != null && ai != null) {
            adj[bi].push(ai);
            indeg[ai]++;
        }
    }

    // 判环
    const indegCopy = [...indeg];
    const q = [];
    for (let i = 0; i < n; i++) if (indegCopy[i] === 0) q.push(i);
    let visited = 0;
    while (q.length) {
        const u = q.shift();
        visited++;
        for (const v of adj[u]) if (--indegCopy[v] === 0) q.push(v);
    }
    if (visited < n) return [];

    // DFS 枚举所有拓扑序
    const results = [];
    const path = [];
    const curIndeg = [...indeg];

    function dfs() {
        if (path.length === n) {
            results.push(path.map(i => modules[i]).join(' '));
            return;
        }
        for (let i = 0; i < n; i++) {
            if (curIndeg[i] !== 0) continue;
            curIndeg[i] = -1;
            path.push(i);
            for (const v of adj[i]) curIndeg[v]--;
            dfs();
            for (const v of adj[i]) curIndeg[v]++;
            path.pop();
            curIndeg[i] = 0;
        }
    }

    dfs();
    return results.sort();
};
