#include <string.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_N 100
#define MAX_RESULT 50000

static int _n;
static int _adj[MAX_N][MAX_N];
static int _adjCnt[MAX_N];
static int _indeg[MAX_N];
static char* _names[MAX_N];

static char* _results[MAX_RESULT];
static int _resultCnt;
static int _path[MAX_N];
static int _pathLen;

static int _cmp_result(const void* a, const void* b) {
    return strcmp(*(const char**)a, *(const char**)b);
}

// 深度优先枚举所有拓扑排序
static void _dfs(int* indeg) {
    if (_pathLen == _n) {
        int totalLen = 0;
        for (int i = 0; i < _n; i++)
            totalLen += strlen(_names[_path[i]]) + 1;
        _results[_resultCnt] = (char*)malloc(totalLen);
        int pos = 0;
        for (int i = 0; i < _n; i++) {
            int len = strlen(_names[_path[i]]);
            memcpy(_results[_resultCnt] + pos, _names[_path[i]], len);
            pos += len;
            if (i < _n - 1) _results[_resultCnt][pos++] = ' ';
        }
        _results[_resultCnt][pos] = '\0';
        _resultCnt++;
        return;
    }
    for (int cand = 0; _resultCnt < MAX_RESULT && cand < _n; cand++) {
        if (indeg[cand] != 0) continue;
        indeg[cand] = -1;
        _path[_pathLen++] = cand;
        for (int k = 0; k < _adjCnt[cand]; k++) indeg[_adj[cand][k]]--;
        _dfs(indeg);
        for (int k = 0; k < _adjCnt[cand]; k++) indeg[_adj[cand][k]]++;
        _pathLen--;
        indeg[cand] = 0;
    }
}

char** allBuildOrders(char** modules, int modulesSize,
                      char*** dependencies, int dependenciesSize, int* returnSize) {
    _n = modulesSize;
    for (int i = 0; i < _n; i++) {
        _names[i] = modules[i];
        _adjCnt[i] = 0;
        _indeg[i] = 0;
    }

    // 建图：a 依赖 b => b -> a
    for (int d = 0; d < dependenciesSize; d++) {
        char* a = dependencies[d][0];
        char* b = dependencies[d][1];
        int ai = -1, bi = -1;
        for (int i = 0; i < _n; i++) {
            if (strcmp(_names[i], a) == 0) ai = i;
            if (strcmp(_names[i], b) == 0) bi = i;
        }
        if (ai >= 0 && bi >= 0) {
            _adj[bi][_adjCnt[bi]++] = ai;
            _indeg[ai]++;
        }
    }

    // Kahn 判环
    int indeg_copy[MAX_N];
    memcpy(indeg_copy, _indeg, sizeof(_indeg));
    int q[MAX_N], h = 0, t = 0;
    for (int i = 0; i < _n; i++)
        if (indeg_copy[i] == 0) q[t++] = i;
    int visited = 0;
    while (h < t) {
        int u = q[h++];
        visited++;
        for (int k = 0; k < _adjCnt[u]; k++) {
            int v = _adj[u][k];
            if (--indeg_copy[v] == 0) q[t++] = v;
        }
    }
    if (visited < _n) {
        *returnSize = 0;
        return NULL;
    }

    _resultCnt = 0;
    _pathLen = 0;
    memcpy(indeg_copy, _indeg, sizeof(_indeg));
    _dfs(indeg_copy);

    qsort(_results, _resultCnt, sizeof(char*), _cmp_result);
    char** result = (char**)malloc(_resultCnt * sizeof(char*));
    for (int i = 0; i < _resultCnt; i++) result[i] = _results[i];
    *returnSize = _resultCnt;
    return result;
}
